UPDATE member
SET member_id=#{memberId}, password=#{password}, name=#{name}, gender=#{gender}, birth=#{birth}, email=#{email}, hp=#{hp},
role=#{role}, grade=#{grade}, point=#{point}, status=#{status}, zip=#{zip}, addr1=#{addr1}, addr2=#{addr2},
last_login_date=#{lastLoginDate}, leave_date=#{leaveDate}
WHERE member_no=#{memberNo}
